#!/usr/bin/env node
// Extract memory values from an ELF binary's loadable (PT_LOAD) segments.
// For each PT_LOAD segment we map its file-backed bytes at the segment's
// virtual address (p_vaddr) and emit every aligned 32-bit little-endian word
// as address -> integer. Output is a JSON object on stdout.

const fs = require('fs');

const path = process.argv[2];
if (!path) {
  process.stderr.write('usage: node extract.js <elf-binary>\n');
  process.exit(1);
}

const buf = fs.readFileSync(path);

// --- ELF header sanity check ---
if (buf.length < 64 ||
    buf[0] !== 0x7f || buf[1] !== 0x45 || buf[2] !== 0x4c || buf[3] !== 0x46) {
  process.stderr.write('not an ELF file\n');
  process.exit(1);
}

const ei_class = buf[4]; // 1 = 32-bit, 2 = 64-bit
const ei_data = buf[5];  // 1 = little endian, 2 = big endian
if (ei_data !== 1) {
  process.stderr.write('only little-endian ELF supported\n');
  process.exit(1);
}
const is64 = ei_class === 2;

// Program header table location.
let e_phoff, e_phentsize, e_phnum;
if (is64) {
  e_phoff = Number(buf.readBigUInt64LE(0x20));
  e_phentsize = buf.readUInt16LE(0x36);
  e_phnum = buf.readUInt16LE(0x38);
} else {
  e_phoff = buf.readUInt32LE(0x1c);
  e_phentsize = buf.readUInt16LE(0x2a);
  e_phnum = buf.readUInt16LE(0x2c);
}

const PT_LOAD = 1;
const result = {};

for (let i = 0; i < e_phnum; i++) {
  const ph = e_phoff + i * e_phentsize;
  const p_type = buf.readUInt32LE(ph);
  if (p_type !== PT_LOAD) continue;

  let p_offset, p_vaddr, p_filesz;
  if (is64) {
    p_offset = Number(buf.readBigUInt64LE(ph + 0x08));
    p_vaddr = Number(buf.readBigUInt64LE(ph + 0x10));
    p_filesz = Number(buf.readBigUInt64LE(ph + 0x20));
  } else {
    p_offset = buf.readUInt32LE(ph + 0x04);
    p_vaddr = buf.readUInt32LE(ph + 0x08);
    p_filesz = buf.readUInt32LE(ph + 0x10);
  }

  // Emit aligned 32-bit little-endian words from the file-backed bytes.
  for (let off = 0; off + 4 <= p_filesz; off += 4) {
    const filepos = p_offset + off;
    if (filepos + 4 > buf.length) break;
    const val = buf.readUInt32LE(filepos);
    result[p_vaddr + off] = val;
  }
}

process.stdout.write(JSON.stringify(result));
process.stdout.write('\n');

